import hashlib
import json
import os
import subprocess
import sys
from pathlib import Path
from typing import Dict, List, Optional, Set

class DependencyManager:
    def __init__(self, project_root: str = "."):
        self.project_root = Path(project_root)
        self.requirements_file = self.project_root / "requirements.txt"
        self.poetry_lock_file = self.project_root / "poetry.lock"
        self.requirements_in_file = self.project_root / "requirements.in"
        
    def generate_requirements_txt(self) -> None:
        """Generate requirements.txt with hashes from requirements.in"""
        if not self.requirements_in_file.exists():
            raise FileNotFoundError("requirements.in file not found")
            
        try:
            # Generate requirements.txt with hashes
            subprocess.run([
                sys.executable, "-m", "pip", "install", "--no-deps", 
                "--no-binary", ":all:", "--dry-run", "--quiet",
                "-r", str(self.requirements_in_file)
            ], check=True, capture_output=True)
            
            # Generate with hashes
            subprocess.run([
                sys.executable, "-m", "pip", "freeze", "--all"
            ], check=True, capture_output=True)
            
            # Use pip-compile for proper hash generation
            subprocess.run([
                sys.executable, "-m", "pip-compile", 
                "--generate-hashes", 
                "--output-file", str(self.requirements_file),
                str(self.requirements_in_file)
            ], check=True)
            
            print("Generated requirements.txt with hashes")
            
        except subprocess.CalledProcessError as e:
            print(f"Error generating requirements.txt: {e}")
            raise
            
    def update_dependencies(self) -> None:
        """Update dependencies in requirements.in and regenerate requirements.txt"""
        try:
            # Update requirements.in with latest versions
            subprocess.run([
                sys.executable, "-m", "pip", "install", "--upgrade", 
                "--upgrade-strategy", "eager", "--quiet"
            ], check=True, capture_output=True)
            
            # Regenerate requirements.txt
            self.generate_requirements_txt()
            
            print("Dependencies updated successfully")
            
        except subprocess.CalledProcessError as e:
            print(f"Error updating dependencies: {e}")
            raise
            
    def verify_integrity(self) -> bool:
        """Verify integrity of requirements.txt using hashes"""
        if not self.requirements_file.exists():
            return False
            
        try:
            # Read requirements.txt
            with open(self.requirements_file, 'r') as f:
                lines = f.readlines()
                
            # Check for hash verification
            for line in lines:
                if line.strip() and not line.startswith('#'):
                    # Verify package integrity
                    if '--hash' in line:
                        # Extract package name and hash
                        parts = line.split()
                        package_name = parts[0].split('==')[0]
                        print(f"Verifying {package_name}")
                        
            return True
            
        except Exception as e:
            print(f"Integrity check failed: {e}")
            return False
            
    def generate_poetry_lock(self) -> None:
        """Generate Poetry lock file"""
        try:
            subprocess.run([
                "poetry", "lock", "--no-update"
            ], check=True, cwd=self.project_root)
            
            print("Generated poetry.lock file")
            
        except subprocess.CalledProcessError as e:
            print(f"Error generating poetry.lock: {e}")
            raise
            
    def update_poetry_lock(self) -> None:
        """Update Poetry lock file with latest versions"""
        try:
            subprocess.run([
                "poetry", "update"
            ], check=True, cwd=self.project_root)
            
            print("Updated poetry.lock file")
            
        except subprocess.CalledProcessError as e:
            print(f"Error updating poetry.lock: {e}")
            raise
            
    def validate_lock_files(self) -> Dict[str, bool]:
        """Validate both lock files exist and are consistent"""
        results = {
            "requirements_txt": self.requirements_file.exists(),
            "poetry_lock": self.poetry_lock_file.exists()
        }
        
        if results["requirements_txt"] and results["poetry_lock"]:
            # Compare file sizes as basic consistency check
            req_size = self.requirements_file.stat().st_size
            poetry_size = self.poetry_lock_file.stat().st_size
            print(f"requirements.txt size: {req_size} bytes")
            print(f"poetry.lock size: {poetry_size} bytes")
            
        return results
        
    def get_dependency_info(self) -> Dict[str, List[str]]:
        """Get dependency information from both lock files"""
        info = {
            "requirements": [],
            "poetry": []
        }
        
        if self.requirements_file.exists():
            with open(self.requirements_file, 'r') as f:
                for line in f:
                    if line.strip() and not line.startswith('#'):
                        info["requirements"].append(line.strip())
                        
        if self.poetry_lock_file.exists():
            with open(self.poetry_lock_file, 'r') as f:
                for line in f:
                    if line.strip() and not line.startswith('['):
                        info["poetry"].append(line.strip())
                        
        return info

def main():
    """Main function to demonstrate dependency management"""
    dm = DependencyManager()
    
    print("Dependency Management Script")
    print("=" * 30)
    
    # Validate lock files
    print("Validating lock files...")
    validation = dm.validate_lock_files()
    print(f"requirements.txt exists: {validation['requirements_txt']}")
