    # Generate requirements.txt if needed
    if not dm.requirements_file.exists():
        print("Generating requirements.txt...")
        dm.generate_requirements_txt()
    
    # Verify integrity
    print("Verifying integrity...")
    integrity_ok = dm.verify_integrity()
