    # Show dependency info
    print("\nDependency Information:")
    info = dm.get_dependency_info()
    print("Requirements.txt dependencies:")
    for dep in info["requirements"][:5]:  # Show first 5
        print(f"  {dep}")
        
    print("Poetry dependencies:")
    for dep in info["poetry"][:5]:  # Show first 5
        print(f"  {dep}")

